# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests
from requests.auth import HTTPBasicAuth

# Configuration
RABBITMQ_MANAGEMENT_URL = "http://localhost:15672/api"
ADMIN_USERNAME = "admin"
ADMIN_PASSWORD = "admin"

VHOSTS = [
    {"name": "/app1", "description": "Virtual host for application 1"},
    {"name": "/app2", "description": "Virtual host for application 2"}
]

USERS = [
    {"username": "user1", "password": "pass1", "vhost": "/app1", "permissions": {"configure": ".*", "write": ".*", "read": ".*"}},
    {"username": "user2", "password": "pass2", "vhost": "/app2", "permissions": {"configure": ".*", "write": ".*", "read": ".*"}}
]

# Create virtual hosts
for vhost in VHOSTS:
    response = requests.put(f"{RABBITMQ_MANAGEMENT_URL}/vhosts/{vhost['name']}",
                            auth=HTTPBasicAuth(ADMIN_USERNAME, ADMIN_PASSWORD),
                            json={"name": vhost['name'], "description": vhost['description']})
    if response.status_code == 201:
        print(f"Virtual host {vhost['name']} created successfully.")
    else:
        print(f"Failed to create virtual host {vhost['name']}. Status code: {response.status_code}")

# Create users and set permissions
for user in USERS:
    # Create user
    response = requests.put(f"{RABBITMQ_MANAGEMENT_URL}/users/{user['username']}",
                            auth=HTTPBasicAuth(ADMIN_USERNAME, ADMIN_PASSWORD),
                            json={"password": user['password'], "tags": ""})
    if response.status_code == 201:
        print(f"User {user['username']} created successfully.")
    else:
        print(f"Failed to create user {user['username']}. Status code: {response.status_code}")

    # Set permissions
    response = requests.put(f"{RABBITMQ_MANAGEMENT_URL}/permissions/{user['vhost']}/{user['username']}",
                            auth=HTTPBasicAuth(ADMIN_USERNAME, ADMIN_PASSWORD),
                            json=user['permissions'])
    if response.status_code == 201:
        print(f"Permissions for user {user['username']} in vhost {user['vhost']} set successfully.")
    else:
        print(f"Failed to set permissions for user {user['username']} in vhost {user['vhost']}. Status code: {response.status_code}")